const pptxgen = require("pptxgenjs");
const React = require("react");
const ReactDOMServer = require("react-dom/server");
const sharp = require("sharp");
const FA = require("react-icons/fa");

// ---------- palette / type ----------
const C = {
  bgDark: "0F1A2E", navy: "16264A", panel: "1B2D52",
  teal: "1C7293", mint: "02C39A", amber: "F4A93C", indigo: "5C6BC0",
  light: "F4F6F8", card: "FFFFFF", ink: "1E2A3A", muted: "5E6E80",
  white: "FFFFFF", ice: "CFE3EC", hair: "E2E8EF", grayPanel: "ECEFF3",
  mintTint: "E7F7F2", red: "D9534F",
};
const HEAD = "Trebuchet MS";
const BODY = "Calibri";
const W = 13.33, H = 7.5, M = 0.7, CW = W - 2 * M;

const makeShadow = () => ({ type: "outer", color: "1E2A3A", blur: 9, offset: 3, angle: 135, opacity: 0.16 });
const softShadow = () => ({ type: "outer", color: "1E2A3A", blur: 7, offset: 2, angle: 135, opacity: 0.12 });

// ---------- icon rasterizer ----------
const _cache = {};
async function icon(name, colorHex) {
  const key = name + colorHex;
  if (_cache[key]) return _cache[key];
  const Comp = FA[name];
  if (!Comp) throw new Error("missing icon " + name);
  const svg = ReactDOMServer.renderToStaticMarkup(
    React.createElement(Comp, { color: "#" + colorHex, size: "256" })
  );
  const png = await sharp(Buffer.from(svg)).png().toBuffer();
  const data = "image/png;base64," + png.toString("base64");
  _cache[key] = data;
  return data;
}

(async () => {
  const pres = new pptxgen();
  pres.layout = "LAYOUT_WIDE";
  pres.author = "Kalhar Pandya";
  pres.company = "Northeastern University — CS7980";
  pres.title = "GuideMate — Weekly Update (Jun 17, 2026)";

  // ---------- shared helpers ----------
  const rect = pres.shapes.RECTANGLE;
  const oval = pres.shapes.OVAL;

  function footer(slide, n) {
    slide.addShape(rect, { x: M, y: H - 0.5, w: 0.16, h: 0.16, fill: { color: C.mint } });
    slide.addText("GuideMate  ·  CS7980 Capstone", {
      x: M + 0.26, y: H - 0.56, w: 6, h: 0.3, fontSize: 9, color: C.muted,
      fontFace: BODY, align: "left", valign: "middle", margin: 0,
    });
    slide.addText(String(n).padStart(2, "0"), {
      x: W - 1.2, y: H - 0.56, w: 0.6, h: 0.3, fontSize: 9, color: C.muted,
      fontFace: BODY, align: "right", valign: "middle", margin: 0,
    });
  }

  async function header(slide, eyebrow, title, iconName, accent) {
    slide.addShape(oval, { x: M, y: 0.55, w: 0.74, h: 0.74, fill: { color: accent }, shadow: softShadow() });
    slide.addImage({ data: await icon(iconName, "FFFFFF"), x: M + 0.19, y: 0.74, w: 0.36, h: 0.36 });
    slide.addText(eyebrow.toUpperCase(), {
      x: M + 0.98, y: 0.5, w: CW - 1, h: 0.26, fontSize: 11, bold: true,
      color: C.teal, fontFace: HEAD, charSpacing: 2, align: "left", valign: "middle", margin: 0,
    });
    slide.addText(title, {
      x: M + 0.96, y: 0.73, w: CW - 1, h: 0.56, fontSize: 28, bold: true,
      color: C.ink, fontFace: HEAD, align: "left", valign: "middle", margin: 0,
    });
  }

  function lightSlide() {
    const s = pres.addSlide();
    s.background = { color: C.light };
    return s;
  }

  function card(slide, x, y, w, h, accent) {
    slide.addShape(rect, { x, y, w, h, fill: { color: C.card }, line: { color: C.hair, width: 1 }, shadow: softShadow() });
    slide.addShape(rect, { x, y, w: 0.09, h, fill: { color: accent } });
  }

  function decorDark(slide) {
