const pptxgen = require("pptxgenjs");
const React = require("react");
const ReactDOMServer = require("react-dom/server");
const sharp = require("sharp");
const FA = require("react-icons/fa");

// ---------- palette / type ----------
const C = {
  bgDark: "0F1A2E", navy: "16264A", panel: "1B2D52",
  teal: "1C7293", mint: "02C39A", amber: "F4A93C", indigo: "5C6BC0",
  light: "F4F6F8", card: "FFFFFF", ink: "1E2A3A", muted: "5E6E80",
  white: "FFFFFF", ice: "CFE3EC", hair: "E2E8EF", grayPanel: "ECEFF3",
  mintTint: "E7F7F2", red: "D9534F",
};
const HEAD = "Trebuchet MS";
const BODY = "Calibri";
const W = 13.33, H = 7.5, M = 0.7, CW = W - 2 * M;

const makeShadow = () => ({ type: "outer", color: "1E2A3A", blur: 9, offset: 3, angle: 135, opacity: 0.16 });
const softShadow = () => ({ type: "outer", color: "1E2A3A", blur: 7, offset: 2, angle: 135, opacity: 0.12 });

// ---------- icon rasterizer ----------
const _cache = {};
async function icon(name, colorHex) {
  const key = name + colorHex;
  if (_cache[key]) return _cache[key];
  const Comp = FA[name];
  if (!Comp) throw new Error("missing icon " + name);
  const svg = ReactDOMServer.renderToStaticMarkup(
    React.createElement(Comp, { color: "#" + colorHex, size: "256" })
  );
  const png = await sharp(Buffer.from(svg)).png().toBuffer();
  const data = "image/png;base64," + png.toString("base64");
  _cache[key] = data;
  return data;
}

(async () => {
  const pres = new pptxgen();
  pres.layout = "LAYOUT_WIDE";
  pres.author = "Kalhar Pandya";
  pres.company = "Northeastern University — CS7980";
  pres.title = "GuideMate — Weekly Update (Jun 17, 2026)";

  // ---------- shared helpers ----------
  const rect = pres.shapes.RECTANGLE;
  const oval = pres.shapes.OVAL;

  function footer(slide, n) {
    slide.addShape(rect, { x: M, y: H - 0.5, w: 0.16, h: 0.16, fill: { color: C.mint } });
    slide.addText("GuideMate  ·  CS7980 Capstone", {
      x: M + 0.26, y: H - 0.56, w: 6, h: 0.3, fontSize: 9, color: C.muted,
      fontFace: BODY, align: "left", valign: "middle", margin: 0,
    });
    slide.addText(String(n).padStart(2, "0"), {
      x: W - 1.2, y: H - 0.56, w: 0.6, h: 0.3, fontSize: 9, color: C.muted,
      fontFace: BODY, align: "right", valign: "middle", margin: 0,
    });
  }

  async function header(slide, eyebrow, title, iconName, accent) {
    slide.addShape(oval, { x: M, y: 0.55, w: 0.74, h: 0.74, fill: { color: accent }, shadow: softShadow() });
    slide.addImage({ data: await icon(iconName, "FFFFFF"), x: M + 0.19, y: 0.74, w: 0.36, h: 0.36 });
    slide.addText(eyebrow.toUpperCase(), {
      x: M + 0.98, y: 0.5, w: CW - 1, h: 0.26, fontSize: 11, bold: true,
      color: C.teal, fontFace: HEAD, charSpacing: 2, align: "left", valign: "middle", margin: 0,
    });
    slide.addText(title, {
      x: M + 0.96, y: 0.73, w: CW - 1, h: 0.56, fontSize: 28, bold: true,
      color: C.ink, fontFace: HEAD, align: "left", valign: "middle", margin: 0,
    });
  }

  function lightSlide() {
    const s = pres.addSlide();
    s.background = { color: C.light };
    return s;
  }

  function card(slide, x, y, w, h, accent) {
    slide.addShape(rect, { x, y, w, h, fill: { color: C.card }, line: { color: C.hair, width: 1 }, shadow: softShadow() });
    slide.addShape(rect, { x, y, w: 0.09, h, fill: { color: accent } });
  }

  function decorDark(slide) {
    slide.addShape(oval, { x: 10.0, y: -1.7, w: 5.6, h: 5.6, fill: { color: C.mint, transparency: 90 } });
    slide.addShape(oval, { x: -1.4, y: 4.6, w: 3.8, h: 3.8, fill: { color: C.teal, transparency: 86 } });
    slide.addShape(oval, { x: 9.4, y: 3.6, w: 4.6, h: 4.6, fill: { color: "FFFFFF", transparency: 100 }, line: { color: C.mint, width: 1.25 } });
  }

  // =================================================================
  // SLIDE 1 — TITLE
  // =================================================================
  {
    const s = pres.addSlide();
    s.background = { color: C.bgDark };
    decorDark(s);
    // accent bar
    s.addShape(rect, { x: M, y: 2.32, w: 0.13, h: 1.95, fill: { color: C.mint } });
    s.addText("CS7980 CAPSTONE   ·   WEEKLY UPDATE", {
      x: M + 0.35, y: 1.75, w: 10, h: 0.4, fontSize: 13, bold: true, color: C.mint,
      fontFace: HEAD, charSpacing: 3, align: "left", valign: "middle", margin: 0,
    });
    s.addText("GuideMate", {
      x: M + 0.32, y: 2.18, w: 11, h: 1.25, fontSize: 60, bold: true, color: C.white,
      fontFace: HEAD, align: "left", valign: "middle", margin: 0,
    });
    s.addText("TurtleBot 4 Guide Robot — Progress Update", {
      x: M + 0.35, y: 3.5, w: 11, h: 0.55, fontSize: 22, color: C.ice,
      fontFace: BODY, align: "left", valign: "middle", margin: 0,
    });
    s.addText("Wednesday, June 17, 2026", {
      x: M + 0.35, y: 4.12, w: 11, h: 0.4, fontSize: 14, color: C.mint,
      fontFace: BODY, align: "left", valign: "middle", margin: 0,
    });
    // robot badge top-right
    s.addShape(oval, { x: 11.05, y: 0.85, w: 1.25, h: 1.25, fill: { color: C.mint } });
    s.addImage({ data: await icon("FaRobot", "0F1A2E"), x: 11.36, y: 1.16, w: 0.63, h: 0.63 });
    // team line
    s.addShape(rect, { x: M, y: 6.35, w: 0.16, h: 0.16, fill: { color: C.amber } });
    s.addText("Kalhar Pandya   ·   Sibgha Ahmad   ·   Shibo Bai   ·   Fazheng Han", {
      x: M + 0.26, y: 6.18, w: 11.5, h: 0.45, fontSize: 13.5, color: C.ice,
      fontFace: BODY, align: "left", valign: "middle", margin: 0,
    });
  }

  // =================================================================
  // SLIDE 2 — AGENDA / WORKSTREAMS
  // =================================================================
  {
    const s = lightSlide();
    await header(s, "Agenda", "Four Workstreams", "FaListUl", C.teal);
    const cards = [
      { owner: "Kalhar Pandya", title: "Connectivity & Cloud", desc: "Campus networking, multi-agent setup, remote access, AWS.", ic: "FaNetworkWired", ac: C.mint },
      { owner: "Shibo Bai", title: "Simulation & Framework", desc: "Gazebo, exposing the API, Nav2, the AWS bridge.", ic: "FaCube", ac: C.teal },
      { owner: "Fazheng Han", title: "Cybersecurity & Guardrails", desc: "Zero-trust model I/O, ROS & WiFi threat model.", ic: "FaShieldAlt", ac: C.amber },
      { owner: "Sibgha Ahmad", title: "Accessibility & Policy", desc: "Accessible-by-design, UX, deployment readiness.", ic: "FaUniversalAccess", ac: C.indigo },
    ];
    const cw = 2.78, gap = (CW - 4 * cw) / 3, y = 1.95, h = 3.85;
    for (let i = 0; i < cards.length; i++) {
      const x = M + i * (cw + gap);
      const c = cards[i];
      card(s, x, y, cw, h, c.ac);
      s.addShape(oval, { x: x + 0.32, y: y + 0.36, w: 0.82, h: 0.82, fill: { color: c.ac } });
      s.addImage({ data: await icon(c.ic, "FFFFFF"), x: x + 0.53, y: y + 0.57, w: 0.4, h: 0.4 });
      s.addText(c.owner.toUpperCase(), {
        x: x + 0.32, y: y + 1.42, w: cw - 0.6, h: 0.3, fontSize: 10.5, bold: true,
        color: c.ac, fontFace: HEAD, charSpacing: 1, align: "left", valign: "middle", margin: 0,
      });
      s.addText(c.title, {
        x: x + 0.32, y: y + 1.74, w: cw - 0.58, h: 0.78, fontSize: 17, bold: true,
        color: C.ink, fontFace: HEAD, align: "left", valign: "top", margin: 0,
      });
      s.addText(c.desc, {
        x: x + 0.32, y: y + 2.55, w: cw - 0.56, h: 1.1, fontSize: 11.5,
        color: C.muted, fontFace: BODY, align: "left", valign: "top", margin: 0, lineSpacingMultiple: 1.05,
      });
    }
    // process strip
    s.addShape(rect, { x: M, y: 6.15, w: CW, h: 0.62, fill: { color: C.navy } });
    s.addImage({ data: await icon("FaArrowRight", "02C39A"), x: M + 0.3, y: 6.34, w: 0.26, h: 0.26 });
    s.addText("Process:  each owner contributes points  →  consolidate in Google Slides  →  export to PowerPoint", {
      x: M + 0.75, y: 6.15, w: CW - 1, h: 0.62, fontSize: 12.5, color: C.ice,
      fontFace: BODY, align: "left", valign: "middle", margin: 0,
    });
    footer(s, 2);
  }

  // =================================================================
  // SLIDE 3 — PROJECT RECAP
  // =================================================================
  {
    const s = lightSlide();
