      { text: " platform, navigating the Northeastern campus to help people get where they need to go.", options: {} },
    ], { x: lx, y: ly, w: lw, h: 1.3, fontSize: 17, color: C.ink, fontFace: BODY, align: "left", valign: "top", margin: 0, lineSpacingMultiple: 1.12 });

    s.addText("Direction this term:", {
      x: lx, y: ly + 1.5, w: lw, h: 0.4, fontSize: 13, bold: true, color: C.ink,
      fontFace: HEAD, charSpacing: 1, align: "left", valign: "middle", margin: 0,
    });
    const dirs = [
      { t: "Accessible", d: "usable by everyone, by design", ic: "FaUniversalAccess", ac: C.indigo },
      { t: "Deployable", d: "ready to run beyond the lab", ic: "FaGlobe", ac: C.mint },
