const pptxgen = require("pptxgenjs");
const React = require("react");
const ReactDOMServer = require("react-dom/server");
const sharp = require("sharp");
const FA = require("react-icons/fa");

// ---------- palette (warm: terracotta / sage / ochre / plum on cream) ----------
const C = {
  dark:   "2E2536", // deep aubergine - dark slides
  ink:    "382F3C", // body/heading text on light
  clay:   "C25A40", // terracotta - primary accent
  sage:   "5E8268", // sage green - secondary
  ochre:  "D89A4A", // warm gold - tertiary
  plum:   "8C6A9E", // muted orchid - quaternary
  rose:   "B5546A", // for negative/decision markers
  cream:  "F3ECE0", // content background (warm)
  paper:  "FBF6EE", // card background (warm off-white)
  glyph:  "FBF6EE", // cream glyph on dark/colored
  muted:  "7C6F75", // muted text
  line:   "E4D9C9", // hairline
  panel:  "EBE1D2", // light warm panel
  tintClay:  "F4E1D9",
  tintSage:  "E2EAE0",
  tintOchre: "F5E9D4",
  tintPlum:  "ECE3F1",
};
const HEAD = "Georgia";
const BODY = "Segoe UI";
const W = 13.33, H = 7.5, M = 0.7, CW = W - 2 * M;

const AC = {
  clay:  { c: C.clay,  g: C.glyph, t: C.tintClay },
  sage:  { c: C.sage,  g: C.glyph, t: C.tintSage },
  ochre: { c: C.ochre, g: C.dark,  t: C.tintOchre },
  plum:  { c: C.plum,  g: C.glyph, t: C.tintPlum },
};

const softShadow = () => ({ type: "outer", color: "2E2536", blur: 7, offset: 2, angle: 135, opacity: 0.12 });
const medShadow  = () => ({ type: "outer", color: "2E2536", blur: 10, offset: 3, angle: 135, opacity: 0.18 });

// ---------- icon rasterizer ----------
const _cache = {};
async function icon(name, hex) {
  const key = name + hex;
  if (_cache[key]) return _cache[key];
  const Comp = FA[name];
  if (!Comp) throw new Error("missing icon " + name);
  const svg = ReactDOMServer.renderToStaticMarkup(React.createElement(Comp, { color: "#" + hex, size: "256" }));
  const png = await sharp(Buffer.from(svg)).png().toBuffer();
  _cache[key] = "image/png;base64," + png.toString("base64");
  return _cache[key];
}

(async () => {
  const pres = new pptxgen();
  pres.layout = "LAYOUT_WIDE";
  pres.author = "Kalhar Pandya";
  pres.company = "Northeastern University - CS7980";
  pres.title = "GuideMate - Weekly Update (Jun 17, 2026)";

  const RR = pres.shapes.ROUNDED_RECTANGLE;
  const RECT = pres.shapes.RECTANGLE;
  const OVAL = pres.shapes.OVAL;

  function lightSlide() { const s = pres.addSlide(); s.background = { color: C.cream }; return s; }

  // rounded-square icon badge (solid accent fill, cream/dark glyph)
  async function badge(s, x, y, sz, accent, iconName) {
    const a = AC[accent];
    s.addShape(RR, { x, y, w: sz, h: sz, fill: { color: a.c }, rectRadius: Math.min(0.12, sz * 0.22), shadow: softShadow() });
    const gi = sz * 0.5;
    s.addImage({ data: await icon(iconName, a.g), x: x + (sz - gi) / 2, y: y + (sz - gi) / 2, w: gi, h: gi });
  }

  // tinted card with full border (no one-side bars)
  function tcard(s, x, y, w, h, accent) {
    s.addShape(RR, { x, y, w, h, fill: { color: AC[accent].t }, line: { color: C.line, width: 1 }, rectRadius: 0.12, shadow: softShadow() });
  }
  function paperCard(s, x, y, w, h) {
    s.addShape(RR, { x, y, w, h, fill: { color: C.paper }, line: { color: C.line, width: 1 }, rectRadius: 0.12, shadow: softShadow() });
  }

