    await badge(s, M, 0.55, 0.74, accent, iconName);
    s.addText(eyebrow.toUpperCase(), {
      x: M + 0.98, y: 0.5, w: CW - 1, h: 0.26, fontSize: 11, bold: true, color: AC[accent].c,
      fontFace: BODY, charSpacing: 2, align: "left", valign: "middle", margin: 0,
    });
    s.addText(title, {
      x: M + 0.96, y: 0.74, w: CW - 1, h: 0.6, fontSize: 27, bold: true, color: C.ink,
      fontFace: HEAD, align: "left", valign: "middle", margin: 0,
    });
  }

  function footer(s, n) {
    s.addShape(RR, { x: M, y: H - 0.5, w: 0.16, h: 0.16, fill: { color: C.clay }, rectRadius: 0.04 });
