  }

  // =================================================================
  // SLIDE 1 - TITLE
  // =================================================================
  {
    const s = pres.addSlide();
    s.background = { color: C.dark };
    decorDark(s);
    await badge(s, 11.0, 0.78, 1.3, "sage", "FaRobot");
    s.addText("CS7980 CAPSTONE     ·     WEEKLY UPDATE", {
      x: M, y: 1.7, w: 10.5, h: 0.4, fontSize: 13, bold: true, color: C.ochre, fontFace: BODY, charSpacing: 3, align: "left", valign: "middle", margin: 0,
    });
    s.addText("GuideMate", { x: M - 0.04, y: 2.12, w: 11, h: 1.35, fontSize: 66, bold: true, color: C.cream, fontFace: HEAD, align: "left", valign: "middle", margin: 0 });
    s.addText("TurtleBot 4 Guide Robot:  Progress Update", { x: M, y: 3.62, w: 11, h: 0.55, fontSize: 22, color: C.cream, fontFace: BODY, align: "left", valign: "middle", margin: 0 });
    s.addText("Wednesday, June 17, 2026", { x: M, y: 4.24, w: 11, h: 0.4, fontSize: 14, color: C.ochre, fontFace: BODY, align: "left", valign: "middle", margin: 0 });
    s.addShape(RR, { x: M, y: 6.32, w: 0.16, h: 0.16, fill: { color: C.clay }, rectRadius: 0.04 });
    s.addText("Kalhar Pandya     ·     Sibgha Ahmad     ·     Shibo Bai     ·     Fazheng Han", {
      x: M + 0.28, y: 6.15, w: 12, h: 0.45, fontSize: 13.5, color: C.cream, fontFace: BODY, align: "left", valign: "middle", margin: 0,
    });
  }

  // =================================================================
  // SLIDE 2 - WORKSTREAMS
  // =================================================================
  {
    const s = lightSlide();
    await header(s, "Agenda", "Four Workstreams", "FaListUl", "clay");
    const cards = [
      { owner: "Kalhar Pandya", title: "Connectivity & Cloud", desc: "Campus networking, multi-agent setup, remote access, and AWS.", ic: "FaNetworkWired", ac: "clay" },
      { owner: "Shibo Bai", title: "Simulation & Framework", desc: "Gazebo, exposing the API, Nav2, and the AWS bridge.", ic: "FaCube", ac: "sage" },
      { owner: "Fazheng Han", title: "Cybersecurity & Guardrails", desc: "Zero-trust model I/O, plus ROS and WiFi threat modeling.", ic: "FaShieldAlt", ac: "ochre" },
      { owner: "Sibgha Ahmad", title: "Accessibility & Policy", desc: "Accessible by design, UX, and deployment readiness.", ic: "FaUniversalAccess", ac: "plum" },
    ];
