      s.addText(c.owner.toUpperCase(), { x: x + 0.34, y: y + 1.46, w: cw - 0.6, h: 0.3, fontSize: 10.5, bold: true, color: AC[c.ac].c, fontFace: BODY, charSpacing: 1, align: "left", valign: "middle", margin: 0 });
      s.addText(c.title, { x: x + 0.34, y: y + 1.78, w: cw - 0.56, h: 0.8, fontSize: 17, bold: true, color: C.ink, fontFace: HEAD, align: "left", valign: "top", margin: 0 });
      s.addText(c.desc, { x: x + 0.34, y: y + 2.58, w: cw - 0.56, h: 0.95, fontSize: 11.5, color: C.muted, fontFace: BODY, align: "left", valign: "top", margin: 0, lineSpacingMultiple: 1.06 });
    }
    s.addShape(RR, { x: M, y: 6.05, w: CW, h: 0.66, fill: { color: C.dark }, rectRadius: 0.1 });
    s.addImage({ data: await icon("FaArrowRight", C.ochre), x: M + 0.32, y: 6.26, w: 0.26, h: 0.26 });
    s.addText("Process:  each owner contributes points, we consolidate in Google Slides, then export to PowerPoint.", {
