    s.addShape(OVAL, { x: 9.0, y: 3.5, w: 4.9, h: 4.9, fill: { color: C.cream, transparency: 100 }, line: { color: C.ochre, width: 1.25 } });
  }

  // =================================================================
  // SLIDE 1 - TITLE
  // =================================================================
  {
    const s = pres.addSlide();
    s.background = { color: C.dark };
    decorDark(s);
    await badge(s, 11.0, 0.78, 1.3, "sage", "FaRobot");
    s.addText("CS7980 CAPSTONE     ·     WEEKLY UPDATE", {
      x: M, y: 1.7, w: 10.5, h: 0.4, fontSize: 13, bold: true, color: C.ochre, fontFace: BODY, charSpacing: 3, align: "left", valign: "middle", margin: 0,
    });
    s.addText("GuideMate", { x: M - 0.04, y: 2.12, w: 11, h: 1.35, fontSize: 66, bold: true, color: C.cream, fontFace: HEAD, align: "left", valign: "middle", margin: 0 });
