      { ic: "FaTimesCircle", ac: "rose", t: "Multilingual: deprioritized for now", d: "Not the primary goal; easy later, with many failure modes." },
      { ic: "FaTimesCircle", ac: "rose", t: "No live demo Wednesday", d: "Present grounded progress instead." },
      { ic: "FaLayerGroup", ac: "sage", t: "Build core first, expand later", d: "Stabilize the pipeline before adding features." },
    ];
    let dy = ry + 0.42, dh = 1.18, dgap = 0.1;
    for (const d of dec) {
      paperCard(s, rx, dy, rw, dh);
      const gcol = d.ac === "rose" ? C.rose : C.sage;
      s.addImage({ data: await icon(d.ic, gcol), x: rx + 0.34, y: dy + 0.38, w: 0.42, h: 0.42 });
      s.addText(d.t, { x: rx + 0.95, y: dy + 0.16, w: rw - 1.2, h: 0.45, fontSize: 14, bold: true, color: C.ink, fontFace: HEAD, align: "left", valign: "middle", margin: 0 });
      s.addText(d.d, { x: rx + 0.95, y: dy + 0.58, w: rw - 1.2, h: 0.5, fontSize: 11.5, color: C.muted, fontFace: BODY, align: "left", valign: "top", margin: 0 });
      dy += dh + dgap;
    }
    footer(s, 10);
  }

  // =================================================================
  // SLIDE 11 - ROADMAP
  // =================================================================
  {
    const s = lightSlide();
    await header(s, "Roadmap", "Next Steps by Owner", "FaRoute", "clay");
    const steps = [
      { owner: "Kalhar", ac: "clay", ic: "FaNetworkWired", items: ["Point the robot at AWS and open required ports", "Build and consolidate the slide deck"] },
      { owner: "Shibo", ac: "sage", ic: "FaCube", items: ["Nail down the Gazebo API to AWS bridge", "Document the bridge approach for the team"] },
      { owner: "Fazheng", ac: "ochre", ic: "FaShieldAlt", items: ["Expand the guardrails research", "Threat model for ROS and WiFi"] },
      { owner: "Sibgha", ac: "plum", ic: "FaUniversalAccess", items: ["Research accessibility and draft user stories", "Start the mobile app and UI, share the case study"] },
    ];
    const cw = 2.8, gap = (CW - 4 * cw) / 3, y = 1.95, h = 3.55;
    for (let i = 0; i < steps.length; i++) {
      const x = M + i * (cw + gap), c = steps[i];
      tcard(s, x, y, cw, h, c.ac);
      await badge(s, x + 0.32, y + 0.34, 0.78, c.ac, c.ic);
      s.addText(c.owner, { x: x + 1.22, y: y + 0.34, w: cw - 1.35, h: 0.78, fontSize: 17, bold: true, color: C.ink, fontFace: HEAD, align: "left", valign: "middle", margin: 0 });
      s.addText(c.items.map((t) => ({ text: t, options: { bullet: { indent: 14 }, breakLine: true, paraSpaceAfter: 14, color: C.ink, fontSize: 12 } })),
        { x: x + 0.34, y: y + 1.35, w: cw - 0.6, h: h - 1.6, fontFace: BODY, align: "left", valign: "middle", margin: 0, lineSpacingMultiple: 1.04 });
    }
    paperCard(s, M, 5.7, CW, 0.78);
    s.addImage({ data: await icon("FaBookOpen", C.clay), x: M + 0.32, y: 5.95, w: 0.32, h: 0.32 });
    s.addText([
      { text: "References to attach:  ", options: { bold: true, color: C.ink } },
      { text: "accessibility case-study paper (Sibgha), and the guardrails research file in Teams (Fazheng).", options: { color: C.muted } },
    ], { x: M + 0.8, y: 5.7, w: CW - 1, h: 0.78, fontSize: 12.5, fontFace: BODY, align: "left", valign: "middle", margin: 0 });
    footer(s, 11);
  }

  // =================================================================
  // SLIDE 12 - CLOSING
  // =================================================================
  {
    const s = pres.addSlide();
    s.background = { color: C.dark };
    decorDark(s);
    await badge(s, W / 2 - 0.65, 1.2, 1.3, "sage", "FaRobot");
    s.addText("Off the bench. Onto campus.", { x: 1, y: 2.8, w: W - 2, h: 0.95, fontSize: 40, bold: true, color: C.cream, fontFace: HEAD, align: "center", valign: "middle", margin: 0 });
    s.addText("Cloud path validated.  Four workstreams advancing in parallel.", { x: 1, y: 3.8, w: W - 2, h: 0.5, fontSize: 17, color: C.cream, fontFace: BODY, align: "center", valign: "middle", margin: 0 });
    for (let i = 0; i < 3; i++) {
      s.addShape(RR, { x: W / 2 - 0.45 + i * 0.45, y: 4.55, w: 0.16, h: 0.16, fill: { color: [C.clay, C.ochre, C.sage][i] }, rectRadius: 0.04 });
    }
    s.addText("Questions?", { x: 1, y: 4.85, w: W - 2, h: 0.6, fontSize: 22, bold: true, color: C.ochre, fontFace: HEAD, align: "center", valign: "middle", margin: 0 });
    s.addText("Kalhar Pandya     ·     Sibgha Ahmad     ·     Shibo Bai     ·     Fazheng Han", { x: 1, y: 6.4, w: W - 2, h: 0.4, fontSize: 13, color: C.cream, fontFace: BODY, align: "center", valign: "middle", margin: 0 });
  }

  const out = "P:/CS7980/Project-code/GuideMate-Update-2026-06-17.pptx";
  await pres.writeFile({ fileName: out });
  console.log("WROTE " + out);
})().catch((e) => { console.error("BUILD FAILED:", e); process.exit(1); });

